export const ProductCard = ({
  product,
  translate,
  index = 0,
  rowIndex = 0,
}: {
  product: {
    title: string;
    link: string;
    thumbnail: string;
    fallbackSrc?: string;
    priority?: boolean;
  };
  translate: MotionValue<number>;
  index?: number;
  rowIndex?: number;
}) => {
  // Check if on mobile viewport
  const isMobileViewport =
    typeof window !== 'undefined' ? window.matchMedia('(max-width: 767px)').matches : false;
  const cardRef = useRef<HTMLDivElement>(null);
  const [isActive, setIsActive] = useState(false);
  const [isRevealed, setIsRevealed] = useState(false);
  const [isAligned, setIsAligned] = useState(false);
  const [showText, setShowText] = useState(false);
  const prefersReducedMotion = false;

  // Calculate stagger delay based on position (100ms per frame)
  const staggerDelay = (rowIndex * 5 + index) * ANIMATION.STAGGER_OFFSET;

  // ===========================================
  // ANIMATION TIMELINE ORCHESTRATION
  // T=0ms:      Frame enters viewport, snap begins
  // T=0-600ms:  Frame snaps with elastic overshoot
  // T=400ms:    Depth blur activates on inactive frames
  // T=600ms:    Frame settles, Chrome Reveal starts
  // T=800ms:    Text fade delay begins (200ms after settle)
  // T=1100ms:   Text fully visible
  // T=1400ms:   Chrome border fully revealed
  // ===========================================

  useEffect(() => {
    const element = cardRef.current;
    if (!element) return;

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          // Active state: more than 50% visible in viewport center
          const isInCenter = entry.intersectionRatio > 0.5;
          setIsActive(isInCenter);

          // Alignment detection: trigger snap + reveal sequence
          if (entry.isIntersecting && entry.intersectionRatio > 0.3) {
            if (!isAligned) {
              setIsAligned(true);

              // Chrome reveal: trigger after snap settles (600ms)
              if (!isRevealed) {
                setTimeout(
                  () => {
                    setIsRevealed(true);
                  },
                  prefersReducedMotion ? 0 : 600,
                );
              }

              // Text fade: 200ms AFTER frame settles (T=800ms total)
              setTimeout(
                () => {
                  setShowText(true);
                },
                prefersReducedMotion ? 0 : 800,
              );
            }
          }
        });
      },
      {
        threshold: [0.3, 0.5, 0.7],
        rootMargin: '-10% 0px -10% 0px',
      },
    );

    observer.observe(element);
    return () => observer.disconnect();
  }, [isRevealed, isAligned, prefersReducedMotion]);

  // Performance: manage will-change
  useEffect(() => {
    const element = cardRef.current;
    if (!element || prefersReducedMotion) return;

    // Add will-change before animations
    element.style.willChange = 'transform, filter, opacity';

    // Remove after all animations complete (~1500ms)
    const cleanup = setTimeout(() => {
      if (element) element.style.willChange = 'auto';
    }, 1500);

    return () => clearTimeout(cleanup);
  }, [isAligned, prefersReducedMotion]);

  // Generate responsive image sources for optimized images
  const sizes = [400, 640, 960];
  const avifSrcSet = sizes
    .map((size) => `${encodeURI(`${product.thumbnail}-${size}w.avif`)} ${size}w`)
    .join(', ');
  const webpSrcSet = sizes
    .map((size) => `${encodeURI(`${product.thumbnail}-${size}w.webp`)} ${size}w`)
    .join(', ');

  // Determine CSS classes based on state
  const revealClass = isRevealed ? 'chrome-border-reveal revealed' : 'chrome-border-reveal';
  const isHeroLcpCandidate = product.priority === true && rowIndex === 0 && index === 0;

  // Depth blur + chrome glow: inline styles for reliable application
  const frameStyles: React.CSSProperties = prefersReducedMotion
    ? {
        // No filter effects for reduced motion, keep chrome glow
        border: '2px solid var(--accent-chrome)',
        boxShadow: '0 0 20px rgba(var(--accent-chrome-rgb), 0.3)',
      }
    : isActive
      ? {
          // Active: sharp, chrome border + glow
          filter: 'blur(0) brightness(1)',
          opacity: 1,
          border: '2px solid var(--accent-chrome)',
          boxShadow: '0 0 20px rgba(var(--accent-chrome-rgb), 0.3)',
          transition:
            'filter 400ms cubic-bezier(0.4, 0, 0.2, 1), opacity 400ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 400ms ease-out',
        }
      : {
          // Inactive: blurred + darkened
          filter: 'blur(4px) brightness(0.7)',
          opacity: 0.6,
          border: '1px solid rgba(var(--accent-chrome-rgb), 0.2)',
          boxShadow: 'none',
          transition:
            'filter 400ms cubic-bezier(0.4, 0, 0.2, 1), opacity 400ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 400ms ease-out',
        };

  // Desktop-specific styles
  const desktopFrameStyles = !isMobileViewport
    ? {
        maxWidth: `${ANIMATION.FRAME_SIZE_DESKTOP}px`,
        maxHeight: `${ANIMATION.FRAME_SIZE_DESKTOP}px`,
      }
    : {};

  // Framer Motion variants for stagger+snap with elastic overshoot
  const snapVariants = {
    hidden: {
      scale: 0.95,
      opacity: 0,
    },
    visible: {
      scale: 1,
      opacity: 1,
    },
  };

  return (
    <motion.div
      ref={cardRef}
      style={{
        x: translate,
        ...frameStyles,
        ...desktopFrameStyles,
      }}
      className={`group/product aspect-square w-full relative rounded-lg overflow-hidden ${revealClass} max-md:w-25 max-md:flex-none`}
      initial={prefersReducedMotion ? 'visible' : 'hidden'}
      animate={isAligned ? 'visible' : 'hidden'}
      variants={snapVariants}
      transition={
        prefersReducedMotion
          ? { duration: 0 }
          : {
              ...ANIMATION.SNAP_SPRING,
              delay: staggerDelay,
            }
      }
      key={product.title}
      data-revealed={isRevealed}
      data-aligned={isAligned}
    >
      <a href={product.link} className='block group-hover/product:shadow-2xl'>
        <picture>
          <source type='image/avif' srcSet={avifSrcSet} sizes='(max-width: 767px) 100px, 400px' />
          <source type='image/webp' srcSet={webpSrcSet} sizes='(max-width: 767px) 100px, 400px' />
          <img
            src={encodeURI(`${product.thumbnail}-400w.webp`)}
            height='600'
            width='600'
            className='max-w-full object-fill object-top-left absolute h-full w-full inset-0'
            alt={product.title}
            loading={isHeroLcpCandidate ? 'eager' : 'lazy'}
            decoding='async'
            onError={(e) => {
              if (!product.fallbackSrc) return;
              const target = e.target as HTMLImageElement;
              const currentSrc = target.getAttribute('src');
              const nextSrc = encodeURI(product.fallbackSrc);
              if (currentSrc !== nextSrc) {
                target.setAttribute('src', nextSrc);
              }
            }}
          />
        </picture>
      </a>
      <div className='absolute inset-0 h-full w-full opacity-0 group-hover/product:opacity-80 bg-luxury-bg-dark pointer-events-none'></div>
      {/* Text with 200ms delayed fade-in after frame settles */}
      <p
        className='absolute bottom-4 left-4 text-luxury-text-inverse transition-opacity duration-300'
        style={{
          opacity: showText ? 1 : 0,
          transitionDelay: showText ? '0ms' : '0ms',
        }}
      >
        {product.title}
      </p>
    </motion.div>
  );
};

import React, {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  useCallback,
  useTransition,
  ReactNode,
} from 'react';
import {
  getI18nInstance,
  setLocale,
  splitTranslationKey,
  NAMESPACES,
  normalizeLocale,
} from '@/i18n';

// Define supported languages
export type Language = 'de' | 'en';

// Interface for context
export interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: string, options?: Record<string, unknown>) => string;
  isChangingLanguage: boolean;
}

// Create the context
export const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

// Props for the provider
interface LanguageProviderProps {
  children: ReactNode;
}

/**
 * Language Provider Component
 * Manages language state and provides translation functionality
 */
export const LanguageProvider: React.FC<LanguageProviderProps> = ({ children }) => {
  const i18n = getI18nInstance();
  const [language, setLanguageState] = useState<Language>('de');
  const [isPending, startTransition] = useTransition();

  useEffect(() => {
    void setLocale(normalizeLocale(i18n.language));
  }, [i18n]);

  const setLanguage = useCallback(
    (lang: Language) => {
      const nextLanguage = normalizeLocale(lang);
      if (language === nextLanguage && i18n.language === nextLanguage) return;

      startTransition(() => {
        void setLocale(nextLanguage);
      });
    },
    [language, i18n],
  );

  useEffect(() => {
    const handler = (lng: string) => {
      setLanguageState(normalizeLocale(lng));
    };

    setLanguageState(normalizeLocale(i18n.language));
    i18n.on('languageChanged', handler);
    return () => {
      i18n.off('languageChanged', handler);
    };
  }, [i18n]);

  /**
   * Translation function to get string by key
   * Supports nested keys like 'nav.home'
   * Now depends on language state to re-render when language changes
   */
  const t = useMemo(() => {
    return (fullKey: string, options?: Record<string, unknown>): string => {
      const { namespace, key } = splitTranslationKey(fullKey);

      // Check if namespace is loaded for CURRENT language (not just any language)
      if (!i18n.hasResourceBundle(language, namespace)) {
        // Synchronously trigger load - the useTransition in setLanguage handles the async waiting
        void i18n.loadNamespaces([namespace]);
      }

      return i18n.t(key, { ns: namespace, ...options });
    };
  }, [i18n, language]);

  // Context value - memoize to prevent unnecessary re-renders
  const contextValue: LanguageContextType = useMemo(
    () => ({
      language,
      setLanguage,
      t,
      isChangingLanguage: isPending,
    }),
    [language, setLanguage, t, isPending],
  );

  return <LanguageContext.Provider value={contextValue}>{children}</LanguageContext.Provider>;
};

/**
 * Custom hook to use language context
 * Throws error if used outside of LanguageProvider
 */
export const useLanguage = (): LanguageContextType => {
  const context = useContext(LanguageContext);

  if (context === undefined) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }

  return context;
};

import {
  KeyboardEvent,
  useCallback,
  useEffect,
  useRef,
  useState,
  KeyboardEventHandler,
  RefObject,
  FocusEventHandler,
} from 'react';

type KeyHandler = (event: KeyboardEvent) => void;
type FocusHandler = (event: React.FocusEvent) => void;

interface UseKeyboardNavOptions {
  /**
   * Whether the keyboard navigation is currently active
   * @default true
   */
  isActive?: boolean;
  /**
   * Callback when the Escape key is pressed
   */
  onEscape?: KeyHandler;
  /**
   * Callback when the Enter key is pressed
   */
  onEnter?: KeyHandler;
  /**
   * Callback when the Space key is pressed
   */
  onSpace?: KeyHandler;
  /**
   * Callback when the ArrowUp key is pressed
   */
  onArrowUp?: KeyHandler;
  /**
   * Callback when the ArrowDown key is pressed
   */
  onArrowDown?: KeyHandler;
  /**
   * Callback when the ArrowLeft key is pressed
   */
  onArrowLeft?: KeyHandler;
  /**
   * Callback when the ArrowRight key is pressed
   */
  onArrowRight?: KeyHandler;
  /**
   * Callback when the Tab key is pressed
   */
  onTab?: KeyHandler;
  /**
   * Callback when the Home key is pressed
   */
  onHome?: KeyHandler;
  /**
   * Callback when the End key is pressed
   */
  onEnd?: KeyHandler;
  /**
   * Callback when any key is pressed
   */
  onKeyDown?: KeyHandler;
  /**
   * Callback when the element gains focus
   */
  onFocus?: FocusHandler;
  /**
   * Callback when the element loses focus
   */
  onBlur?: FocusHandler;
}

/**
 * Hook for managing keyboard navigation and focus states
 * @param options Configuration options for keyboard navigation
 * @returns Object containing event handlers and focus state
 */
export function useKeyboardNav({
  isActive = true,
  onEscape,
  onEnter,
  onSpace,
  onArrowUp,
  onArrowDown,
  onArrowLeft,
  onArrowRight,
  onTab,
  onHome,
  onEnd,
  onKeyDown,
  onFocus,
  onBlur,
}: UseKeyboardNavOptions = {}) {
  const [isFocused, setIsFocused] = useState(false);
  const elementRef = useRef<HTMLElement>(null);

  const handleKeyDown = useCallback(
    (event: KeyboardEvent) => {
      if (!isActive) return;

      // Call the appropriate handler based on the key
      switch (event.key) {
        case 'Escape':
          onEscape?.(event);
          break;
        case 'Enter':
          onEnter?.(event);
          break;
        case ' ':
          onSpace?.(event);
          break;
        case 'ArrowUp':
          onArrowUp?.(event);
          break;
        case 'ArrowDown':
          onArrowDown?.(event);
          break;
        case 'ArrowLeft':
          onArrowLeft?.(event);
          break;
        case 'ArrowRight':
          onArrowRight?.(event);
          break;
        case 'Tab':
          onTab?.(event);
          break;
        case 'Home':
          onHome?.(event);
          break;
        case 'End':
          onEnd?.(event);
          break;
        default:
          break;
      }

      // Call the user's keydown handler if provided
      onKeyDown?.(event);
    },
    [
      isActive,
      onEscape,
      onEnter,
      onSpace,
      onArrowUp,
      onArrowDown,
      onArrowLeft,
      onArrowRight,
      onTab,
      onHome,
      onEnd,
      onKeyDown,
    ],
  );

  // Handle focus events
  const handleFocus = useCallback<FocusEventHandler>(
    (event) => {
      setIsFocused(true);
      onFocus?.(event);
    },
    [onFocus],
  );

  // Handle blur events
  const handleBlur = useCallback<FocusEventHandler>(
    (event) => {
      setIsFocused(false);
      onBlur?.(event);
    },
    [onBlur],
  );

  // Set up event listeners for focus management
  useEffect(() => {
    const element = elementRef.current;
    if (!element) return;

    element.addEventListener('focusin', handleFocus as any);
    element.addEventListener('focusout', handleBlur as any);

    return () => {
      element.removeEventListener('focusin', handleFocus as any);
      element.removeEventListener('focusout', handleBlur as any);
    };
  }, [handleFocus, handleBlur]);

  // Return the event handlers and focus state
  return {
    onKeyDown: handleKeyDown as unknown as React.KeyboardEventHandler<HTMLElement>,
    onFocus: handleFocus,
    onBlur: handleBlur,
    isFocused,
    ref: elementRef as RefObject<HTMLElement>,
  };
}

interface FocusManagementReturn {
  /**
   * Whether the element is currently focused
   */
  isFocused: boolean;
  /**
   * Focus event handler
   */
  onFocus: FocusEventHandler;
  /**
   * Blur event handler
   */
  onBlur: FocusEventHandler;
  /**
   * Ref to attach to the element
   */
  ref: RefObject<HTMLElement>;
}

/**
 * Hook for managing focus within a component
 * @returns Object containing focus state and event handlers
 */
export const useFocusManagement = (): FocusManagementReturn => {
  const [isFocused, setIsFocused] = useState(false);
  const elementRef = useRef<HTMLElement>(null);

  const handleFocus = useCallback<FocusEventHandler>((event) => {
    setIsFocused(true);
  }, []);

  const handleBlur = useCallback<FocusEventHandler>((event) => {
    setIsFocused(false);
  }, []);

  return {
    isFocused,
    onFocus: handleFocus,
    onBlur: handleBlur,
    ref: elementRef,
  };
};

interface ListNavigationOptions {
  /**
   * Initial selected index
   */
  initialIndex?: number;
  /**
   * Whether to wrap around when navigating past the first or last item
   */
  wrapAround?: boolean;
  /**
   * Whether to focus the selected item
   */
  autoFocus?: boolean;
}

interface ListNavigationReturn {
  /**
   * Currently selected index
   */
  selectedIndex: number;
  /**
   * Set the selected index
   */
  setSelectedIndex: (index: number) => void;
  /**
   * Key down event handler for navigation
   */
  onKeyDown: React.KeyboardEventHandler;
  /**
   * Ref for the container element
   */
  containerRef: RefObject<HTMLElement>;
}

/**
 * Hook for managing keyboard navigation in a list
 * @param itemCount Number of items in the list
 * @param onSelect Callback when an item is selected
 * @param options Configuration options
 * @returns Object containing event handlers and selected index
 */
export const useListNavigation = (
  itemCount: number,
  onSelect: (index: number) => void,
  options: ListNavigationOptions = {},
): ListNavigationReturn => {
  const { initialIndex = 0, wrapAround = true, autoFocus = false } = options;
  const [selectedIndex, setSelectedIndex] = useState(initialIndex);
  const containerRef = useRef<HTMLElement>(null);

  // Focus the selected item when it changes
  useEffect(() => {
    if (autoFocus && containerRef.current) {
      const items = containerRef.current.querySelectorAll<HTMLElement>('[role="option"]');
      if (items[selectedIndex]) {
        items[selectedIndex].focus();
      }
    }
  }, [selectedIndex, autoFocus]);

  // Handle keyboard navigation
  const handleKeyDown = useCallback<React.KeyboardEventHandler>(
    (event) => {
      if (itemCount === 0) return;

      let newIndex = selectedIndex;

      switch (event.key) {
        case 'ArrowDown':
          event.preventDefault();
          newIndex = wrapAround
            ? (selectedIndex + 1) % itemCount
            : Math.min(selectedIndex + 1, itemCount - 1);
          break;
        case 'ArrowUp':
          event.preventDefault();
          newIndex = wrapAround
            ? (selectedIndex - 1 + itemCount) % itemCount
            : Math.max(selectedIndex - 1, 0);
          break;
        case 'Home':
          event.preventDefault();
          newIndex = 0;
          break;
        case 'End':
          event.preventDefault();
          newIndex = itemCount - 1;
          break;
        case 'Enter':
        case ' ':
          event.preventDefault();
          onSelect(selectedIndex);
          return; // Don't update the selected index
        default:
          return; // Don't update the selected index for other keys
      }

      setSelectedIndex(newIndex);
    },
    [itemCount, onSelect, selectedIndex, wrapAround],
  );

  return {
    selectedIndex,
    setSelectedIndex,
    onKeyDown: handleKeyDown,
    containerRef,
  };
};

