💳 Zahlung: ${mapPaymentLabel(data.paymentMethod) || 'Nicht angegeben'}
📝 Details: ${data.projectDetails || 'Keine'}

━━━━━━━━━━━━━━━━━━━
🔥 SCHNELL ZUM KALENDER (EIN KLICK):
━━━━━━━━━━━━━━━━━━━

